test.describe('Admin KPI Card Widget', () => {
  test('should render KPI card with title and value', async ({ page }) => {
    await page.goto('/admin/widgets/kpi-card.html', { waitUntil: 'domcontentloaded' });

    // Check for basic HTML structure
    await expect(page.locator('body')).toBeVisible();

    // KPI card should have title and value elements
    const hasTitle = await page.locator('[class*="title"], h1, h2, h3, h4').count() > 0;
    const hasValue = await page.locator('[class*="value"], [class*="number"], [class*="stat"]').count() > 0;

    expect(hasTitle).toBeTruthy();
  });
});

